        {/* ── Admin login ── */}
        <Route path="/admin/login" element={<AdminLogin />} />

        {/* ── Admin protected routes ── */}
        <Route path="/admin/dashboard" element={
          <AdminLayout title="Dashboard" sub="Real-time attendance overview">
